const items = $input.all();
const linkedinAccounts = [];

function extractAccounts(data) {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') {
    if (data.platform) return [data];
    for (const key of ['data', 'accounts', 'results', 'items']) {
      if (Array.isArray(data[key])) return data[key];
    }
    for (const value of Object.values(data)) {
      if (Array.isArray(value)) return value;
    }
  }
  return [];
}

for (const item of items) {
  const rawAccounts = extractAccounts(item.json);
  for (const acc of rawAccounts) {
    if (acc && acc.platform && typeof acc.platform === 'string') {
      if (acc.platform.toLowerCase() === 'linkedin') {
        linkedinAccounts.push({
          json: {
            ...acc,
            accountId: acc.accountId || acc.id || acc._id,
            accountType: acc.metadata && acc.metadata.accountType
          }
        });
      }
    }
  }
}
return linkedinAccounts;

const items = $input.all();
const results = [];

function getMetricValue(metric) {
  if (metric === null || metric === undefined) return 0;
  if (typeof metric === 'number') return metric;
  if (typeof metric === 'object') {
    if (typeof metric.total === 'number') return metric.total;
    if (typeof metric.value === 'number') return metric.value;
  }
  const parsed = Number(metric);
  return isNaN(parsed) ? 0 : parsed;
}

for (const item of items) {
  const data = item.json;
  const accountId = item.json.accountId || data.accountId;
  const platform = item.json.platform || data.platform || 'linkedin';
  const username = item.json.username || data.username || '';

  let metrics = data.metrics || {};
  if (Array.isArray(data)) {
    metrics = data[0]?.metrics || {};
  }

  results.push({
    json: {
      accountId: accountId,
      platform: platform,
      username: username,
      impressions: getMetricValue(metrics.IMPRESSION || metrics.impressions || metrics.uniqueImpressions),
      members_reached: getMetricValue(metrics.MEMBERS_REACHED || metrics.members_reached || metrics.uniqueImpressionsCount),
      reactions: getMetricValue(metrics.REACTION || metrics.reactions || metrics.likeCount || metrics.likes),
      comments: getMetricValue(metrics.COMMENT || metrics.comments || metrics.commentCount),
      reshares: getMetricValue(metrics.RESHARE || metrics.reshares || metrics.shareCount || metrics.shares),
      post_saves: getMetricValue(metrics.POST_SAVE || metrics.post_saves || metrics.saves),
      post_sends: getMetricValue(metrics.POST_SEND || metrics.post_sends || metrics.sends)
    }
  });
}
return results;

const items = $input.all();
const results = [];

function extractPosts(data) {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') {
    for (const key of ['accounts', 'posts', 'data', 'results']) {
      if (Array.isArray(data[key])) return data[key];
    }
    for (const val of Object.values(data)) {
      if (Array.isArray(val)) return val;
    }
  }
  return [];
}

for (const item of items) {
  const accountId = item.json.accountId || $('Filter LinkedIn Accounts').first().json.accountId;
  const rawPosts = extractPosts(item.json);

  for (const post of rawPosts) {
    if (post && post.id) {
      results.push({
        json: {
          accountId: accountId,
          post_id: post.id,
          content: post.message || post.content || '',
          url: post.permalink || post.url || '',
          published_at: post.createdTime || post.createdAt || post.publishedAt || new Date().toISOString()
        }
      });
    }
  }
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const data = item.json;
  const postId = item.json.postId || (data.analytics && data.analytics[0] && data.analytics[0].postId) || data.postId || item.json.post_id;

  let metrics = {};
  if (data.metrics) {
    metrics = data.metrics;
  } else if (data.analytics && data.analytics[0] && data.analytics[0].metrics) {
    metrics = data.analytics[0].metrics;
  }

  if (postId) {
    results.push({
      json: {
        post_id: postId,
        impressions: metrics.impressions || metrics.IMPRESSION || 0,
        likes: metrics.likes || metrics.REACTION || 0,
        comments: metrics.comments || metrics.COMMENT || 0,
        shares: metrics.shares || metrics.RESHARE || 0,
        clicks: metrics.clicks || metrics.CLICK || 0,
        saves: metrics.saves || metrics.POST_SAVE || 0,
        sends: metrics.sends || metrics.POST_SEND || 0
      }
    });
  }
}
return results;
